// Códigos de status importantes:
// 200 OK, 201 Created, 204 No Content
// 400 Bad Request, 401 Unauthorized, 403 Forbidden
// 404 Not Found, 422 Unprocessable, 429 Too Many Requests
// 500 Internal Server Error

// ===== JWT: estrutura =====
// Header.Payload.Signature
// eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiIxMjMiLCJleHAiOjE3MDB9.xyz

// Decodificar payload (sem verificar assinatura)
function decodeJWT(token) {
  const payload = token.split('.')[1];
  return JSON.parse(atob(payload));
}

// Verificar expiração
function isTokenExpired(token) {
  const { exp } = decodeJWT(token);
  return Date.now() >= exp * 1000;
}

// ===== Armazenamento seguro =====
// ❌ localStorage — vulnerável a XSS
// ✅ httpOnly cookie — servidor seta, JS não acessa
// ✅ Memory (variável) — perdido no refresh

// ===== Refresh Token flow =====
async function fetchWithAuth(url, opts = {}) {
  let token = getAccessToken();
  if (isTokenExpired(token)) {
    token = await refreshAccessToken();
  }
  return fetch(url, {
    ...opts,
    headers: { ...opts.headers, Authorization: `Bearer ${token}` }
  });
}

