// ===== INP: evitar bloqueio da thread principal =====
// Dividir tasks longas com scheduler
async function processarLista(items) {
  for (let i = 0; i < items.length; i++) {
    processar(items[i]);
    if (i % 100 === 0) {
      await new Promise(r => setTimeout(r, 0)); // yield para o browser
    }
  }
}

